"""A readable parser for standard 5-field cron expressions.

The public surface is intentionally small:

    schedule = parse("0 12 * * 1-5")
    schedule.describe()  # -> "At 12:00 on Monday through Friday"

Everything else is a small, single-purpose helper. Reading the file
top-to-bottom should explain the whole design without jumping around:
vocabulary (data types) first, then the public entry point, then the
parsing helpers, and finally the description helpers.
"""

from __future__ import annotations

from dataclasses import dataclass
from typing import Iterable


# ---------------------------------------------------------------------------
# Vocabulary: the data types the rest of the module talks in.
# ---------------------------------------------------------------------------


class CronParseError(ValueError):
    """Raised when an expression is malformed or out of range."""


@dataclass(frozen=True)
class FieldSpec:
    """Describes one position in a cron expression (name and legal bounds)."""

    name: str
    min_value: int
    max_value: int


# The five fields, in the order they appear in an expression.
MINUTE = FieldSpec("minute", 0, 59)
HOUR = FieldSpec("hour", 0, 23)
DAY_OF_MONTH = FieldSpec("day of month", 1, 31)
MONTH = FieldSpec("month", 1, 12)
DAY_OF_WEEK = FieldSpec("day of week", 0, 6)

FIELD_SPECS: tuple[FieldSpec, ...] = (MINUTE, HOUR, DAY_OF_MONTH, MONTH, DAY_OF_WEEK)


@dataclass(frozen=True)
class CronField:
    """One parsed field: the concrete values it matches, plus its raw text.

    The raw text is kept so the description layer can tell *how* a set of
    values was written (a range like ``1-5`` versus a list like ``1,3,5``)
    without re-deriving intent from the numbers.
    """

    raw: str
    values: tuple[int, ...]
    spec: FieldSpec

    @property
    def is_wildcard(self) -> bool:
        return self.raw == "*"

    @property
    def is_step(self) -> bool:
        return "/" in self.raw and "," not in self.raw

    @property
    def step(self) -> int:
        return int(self.raw.split("/")[1]) if self.is_step else 1

    @property
    def is_range(self) -> bool:
        return "-" in self.raw and "," not in self.raw

    @property
    def is_single(self) -> bool:
        return len(self.values) == 1


@dataclass(frozen=True)
class CronSchedule:
    """A fully parsed cron expression."""

    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField

    def describe(self) -> str:
        """Return a human-readable English description of the schedule."""
        time_clause = self._describe_time()
        day_clause = self._describe_days()
        return " ".join(clause for clause in (time_clause, day_clause) if clause)

    # The describe helpers live further down with the other description code.
    def _describe_time(self) -> str:
        return describe_time(self.minute, self.hour)

    def _describe_days(self) -> str:
        return describe_days(self.day_of_month, self.month, self.day_of_week)


# ---------------------------------------------------------------------------
# Public entry point.
# ---------------------------------------------------------------------------


def parse(expression: str) -> CronSchedule:
    """Parse a 5-field cron expression into a :class:`CronSchedule`."""
    fields = expression.split()
    if len(fields) != 5:
        raise CronParseError(
            f"Expected 5 fields (minute hour day month weekday), got {len(fields)}: "
            f"{expression!r}"
        )

    minute, hour, day_of_month, month, day_of_week = (
        parse_field(text, spec) for text, spec in zip(fields, FIELD_SPECS)
    )
    return CronSchedule(minute, hour, day_of_month, month, day_of_week)


# ---------------------------------------------------------------------------
# Field parsing: one shared path for *, ranges, lists, steps, and singles.
# ---------------------------------------------------------------------------


def parse_field(raw: str, spec: FieldSpec) -> CronField:
    """Parse a single field. A field is a comma-separated list of terms."""
    if raw == "":
        raise CronParseError(f"Empty {spec.name} field")

    values: set[int] = set()
    for term in raw.split(","):
        values.update(parse_term(term, spec))

    return CronField(raw=raw, values=tuple(sorted(values)), spec=spec)


def parse_term(term: str, spec: FieldSpec) -> Iterable[int]:
    """Parse one term (``*``, ``a``, ``a-b``, ``*/n``, ``a-b/n``, ``a/n``)."""
    range_text, slash, step_text = term.partition("/")
    step = parse_step(step_text, spec) if slash else 1

    low, high = parse_bounds(range_text, spec, has_step=bool(slash))
    return range(low, high + 1, step)


def parse_bounds(text: str, spec: FieldSpec, has_step: bool) -> tuple[int, int]:
    """Resolve the inclusive [low, high] range a term iterates over."""
    if text == "*":
        return spec.min_value, spec.max_value

    if "-" in text:
        low_text, high_text = text.split("-", 1)
        low, high = parse_value(low_text, spec), parse_value(high_text, spec)
        if low > high:
            raise CronParseError(
                f"Invalid {spec.name} range {text!r}: start is greater than end"
            )
        return low, high

    value = parse_value(text, spec)
    # A bare value with a step (e.g. "5/10") runs from the value to the max.
    return (value, spec.max_value) if has_step else (value, value)


def parse_value(text: str, spec: FieldSpec) -> int:
    """Parse a single integer and confirm it is within the field's bounds."""
    value = parse_int(text, spec)
    if not spec.min_value <= value <= spec.max_value:
        raise CronParseError(
            f"{spec.name} value {value} out of range "
            f"[{spec.min_value}, {spec.max_value}]"
        )
    return value


def parse_step(text: str, spec: FieldSpec) -> int:
    """Parse a step (the number after ``/``); it must be a positive integer."""
    step = parse_int(text, spec)
    if step <= 0:
        raise CronParseError(f"{spec.name} step must be positive, got {step}")
    return step


def parse_int(text: str, spec: FieldSpec) -> int:
    """Parse a plain integer, attributing any failure to the right field."""
    try:
        return int(text)
    except ValueError:
        raise CronParseError(f"Invalid {spec.name} value {text!r}: expected an integer")


# ---------------------------------------------------------------------------
# Description: turn parsed fields into English. Time first, then days.
# ---------------------------------------------------------------------------

WEEKDAY_NAMES = (
    "Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday",
)
MONTH_NAMES = (
    "", "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December",
)


def describe_time(minute: CronField, hour: CronField) -> str:
    """Describe the minute/hour portion (the leading clause)."""
    if minute.is_wildcard and hour.is_wildcard:
        return "Every minute"

    if minute.is_step and hour.is_wildcard:
        return f"Every {minute.step} minutes"

    if minute.values == (0,) and hour.is_step:
        return f"Every {hour.step} hours, on the hour"

    if minute.is_single and hour.is_single:
        return f"At {format_clock(hour.values[0], minute.values[0])}"

    if hour.is_wildcard and minute.is_single:
        return f"At {minute.values[0]} minutes past every hour"

    # General fallback: describe each field plainly.
    return f"At {describe_values(minute)} minutes past hour {describe_values(hour)}"


def describe_days(
    day_of_month: CronField, month: CronField, day_of_week: CronField
) -> str:
    """Describe the day-of-month / month / day-of-week portion (trailing clause)."""
    clauses: list[str] = []

    if not day_of_month.is_wildcard:
        when = "every month" if month.is_wildcard else describe_months(month)
        clauses.append(f"on {describe_month_days(day_of_month)} of {when}")
    elif not month.is_wildcard:
        clauses.append(f"in {describe_months(month)}")

    if not day_of_week.is_wildcard:
        clauses.append(f"on {describe_weekdays(day_of_week)}")

    return " ".join(clauses)


def describe_weekdays(field: CronField) -> str:
    names = [WEEKDAY_NAMES[value] for value in field.values]
    if field.is_range:
        return f"{names[0]} through {names[-1]}"
    return oxford_join(names)


def describe_months(field: CronField) -> str:
    names = [MONTH_NAMES[value] for value in field.values]
    if field.is_range:
        return f"{names[0]} through {names[-1]}"
    return oxford_join(names)


def describe_month_days(field: CronField) -> str:
    days = [ordinal(value) for value in field.values]
    if field.is_range:
        return f"the {days[0]} through the {days[-1]}"
    return "the " + oxford_join(days)


def describe_values(field: CronField) -> str:
    """Plain comma/and join of a field's numeric values (used by fallbacks)."""
    return oxford_join([str(value) for value in field.values])


# ---------------------------------------------------------------------------
# Small formatting utilities.
# ---------------------------------------------------------------------------


def format_clock(hour: int, minute: int) -> str:
    if hour == 0 and minute == 0:
        return "midnight"
    return f"{hour:02d}:{minute:02d}"


def ordinal(n: int) -> str:
    if 11 <= n % 100 <= 13:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(n % 10, "th")
    return f"{n}{suffix}"


def oxford_join(items: list[str]) -> str:
    """Join items with commas and a final 'and' (Oxford comma for 3+)."""
    if len(items) == 1:
        return items[0]
    if len(items) == 2:
        return f"{items[0]} and {items[1]}"
    return ", ".join(items[:-1]) + f", and {items[-1]}"


# ---------------------------------------------------------------------------
# Demo / smoke test.
# ---------------------------------------------------------------------------

if __name__ == "__main__":
    EXAMPLES = [
        ("* * * * *", "Every minute"),
        ("0 12 * * 1-5", "At 12:00 on Monday through Friday"),
        ("*/15 * * * *", "Every 15 minutes"),
        ("0 0 1 * *", "At midnight on the 1st of every month"),
        ("30 8 * * 1,3,5", "At 08:30 on Monday, Wednesday, and Friday"),
        ("0 */2 * * *", "Every 2 hours, on the hour"),
    ]

    for expression, expected in EXAMPLES:
        actual = parse(expression).describe()
        mark = "ok  " if actual == expected else "FAIL"
        print(f"[{mark}] {expression:<16} -> {actual}")
